package net.unit8.souther.runtime;

import java.util.ArrayList;
import java.util.List;

/** List helpers the generated bytecode calls (spec 18.4). A {@code List} value is a
 *  {@link PersistentVector} (structural sharing), so the builders here run in O(1) amortized
 *  ({@link #concat}'s single-element append) or O(n) ({@code sort}) rather than copying the whole
 *  list — which is what turns the fold-derived combinators from O(n²) into O(n). Inputs may be any
 *  {@code java.util.List} (a {@code []} literal is a JDK list, a decoded list comes from Raoh), so
 *  every builder normalizes through {@link PersistentVector#from}. */
public final class Lists {

    private Lists() {}

    /** Safe indexing: {@code Some(element)} when {@code index} is in range, else {@code None}. */
    public static <T> Option<T> get(List<T> list, long index) {
        if (index < 0 || index >= list.size()) {
            return Option.none();
        }
        return Option.some(list.get((int) index));
    }

    /** Immutable concatenation of two lists (spec 18.4, the {@code ++} operator). Grows a
     *  {@link PersistentVector}: {@code from(a)} shares {@code a} when it already is one (O(1)) and
     *  each element of {@code b} is appended in O(1) amortized. In the fold hot path {@code b} is the
     *  singleton {@code [x]}, so {@code acc ++ [x]} is O(1) and {@code List.map}/{@code filter} O(n). */
    public static <T> List<T> concat(List<? extends T> a, List<? extends T> b) {
        PersistentVector<T> out = PersistentVector.from(a);
        for (T x : b) {
            out = out.append(x);
        }
        return out;
    }

    /** The list in reverse order (Elm {@code List.reverse}). A native primitive rather than a fold:
     *  a left fold can only prepend to build a reversed list, and prepending to an array-backed
     *  vector is O(n) per step (O(n²) overall), so reversing walks the input from the end in O(n). */
    public static <T> List<T> reverse(List<? extends T> xs) {
        Object[] a = xs.toArray();
        PersistentVector<T> out = PersistentVector.empty();
        for (int i = a.length - 1; i >= 0; i--) {
            @SuppressWarnings("unchecked")
            T e = (T) a[i];
            out = out.append(e);
        }
        return out;
    }

    /** Sorts by the elements' natural order (Elm {@code List.sort}). The element type is a
     *  {@link Comparable} — {@code String} and the {@code Int}/{@code Decimal} carriers all are —
     *  and the input is left untouched. */
    @SuppressWarnings({"unchecked", "rawtypes"})
    public static <T> List<T> sort(List<? extends T> xs) {
        List<T> out = new ArrayList<>(xs);
        out.sort((a, b) -> ((Comparable) a).compareTo(b));
        return PersistentVector.from(out);
    }

    /** The greatest element by natural order, {@code None} for an empty list (Elm {@code List.maximum}).
     *  The element is a {@link Comparable}, as {@code sort} requires. */
    @SuppressWarnings({"unchecked", "rawtypes"})
    public static <T> Option<T> max(List<? extends T> xs) {
        return extreme(xs, true);
    }

    /** The least element by natural order, {@code None} for an empty list (Elm {@code List.minimum}). */
    @SuppressWarnings({"unchecked", "rawtypes"})
    public static <T> Option<T> min(List<? extends T> xs) {
        return extreme(xs, false);
    }

    /** The first element satisfying {@code p}, or {@code None} if none does (Elm {@code List.Extra
     *  find}). {@code p} is a first-class function value; it is applied to each element in turn. */
    public static <T> Option<T> find(Fn p, List<? extends T> xs) {
        for (T x : xs) {
            if ((Boolean) p.apply(new Object[] {x})) {
                return Option.some(x);
            }
        }
        return Option.none();
    }

    /** Sorts by {@code key(element)}'s natural order, the input untouched (Elm {@code List.sortBy}).
     *  {@code key} maps each element to an ordered value. Each key is computed once (decorate, sort,
     *  undecorate), so a costly key runs {@code O(n)} times, not once per comparison; the sort is stable. */
    @SuppressWarnings({"unchecked", "rawtypes"})
    public static <T> List<T> sortBy(Fn key, List<? extends T> xs) {
        List<Object[]> decorated = new ArrayList<>(xs.size());
        for (T x : xs) {
            decorated.add(new Object[] {x, key.apply(new Object[] {x})});
        }
        decorated.sort((a, b) -> ((Comparable) a[1]).compareTo(b[1]));
        List<T> out = new ArrayList<>(decorated.size());
        for (Object[] pair : decorated) {
            out.add((T) pair[0]);
        }
        return PersistentVector.from(out);
    }

    @SuppressWarnings({"unchecked", "rawtypes"})
    private static <T> Option<T> extreme(List<? extends T> xs, boolean greatest) {
        if (xs.isEmpty()) {
            return Option.none();
        }
        T best = xs.get(0);
        for (T x : xs) {
            int cmp = ((Comparable) x).compareTo(best);
            if (greatest ? cmp > 0 : cmp < 0) {
                best = x;
            }
        }
        return Option.some(best);
    }
}
